        /// <returns><see cref="Task"/>&lt;<see cref="ICreateRetailCustomerApiResponse"/>&gt;</returns>
        public async Task<ICreateRetailCustomerApiResponse?> CreateRetailCustomerOrDefaultAsync(string bankid, CreateRetailCustomerRequest createRetailCustomerRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
